package benchmark

import (
	"fmt"
	"slices"
	"strings"
	"time"

	"github.com/omneval/omneval/internal/domain"
)

// Span represents a span generated by the benchmark harness.
type Span struct {
	SpanID    string
	TraceID   string
	ProjectID string
	ParentID  string
	SpanKind  string
	Name      string
	Input     string
	Output    string
	StartTime time.Time
	EndTime   time.Time
	SendTime  time.Time // set by the harness at send time for latency measurement
}

// TraceGroup is a set of spans that form a single agent trace (one root
// span plus zero or more child spans).
type TraceGroup struct {
	TraceID string
	Spans   []*Span
}

// payloadSize is the target size of both Input and Output for each generated
// span.  ~1.5 KB is a typical chat-style prompt/completion, not large RAG
// context.
const payloadSize = 1500

// sampleKind is the pool of span kinds drawn by GenerateTraces to simulate a
// realistic tool-call / sub-agent fan-out pattern.
var sampleKinds = []string{
	"agent", "tool", "llm", "chain", "retriever",
}

// GenerateTraces creates numTraces multi-span agent traces, each with
// spansPerTrace spans.  The first span is the root (parent_id = ""), the
// remaining spans are children whose parent_id references the root span's
// span_id.  All spans in a group share the same trace_id.
func GenerateTraces(projectID string, numTraces, spansPerTrace int) []*TraceGroup {
	traces := make([]*TraceGroup, 0, numTraces)

	for i := 0; i < numTraces; i++ {
		traceID := fmt.Sprintf("%032x", i+1)
		rootSpanID := fmt.Sprintf("%016x", i+1)
		rootSpan := &Span{
			SpanID:    rootSpanID,
			TraceID:   traceID,
			ProjectID: projectID,
			ParentID:  "",
			SpanKind:  "agent",
			Name:      "agent-main",
			Input:     strings.Repeat("i", payloadSize),
			Output:    strings.Repeat("o", payloadSize),
		}
		// Assign a realistic start time for the root span.
		rootSpan.StartTime = time.Date(2026, 1, 1, 0, 0, 0, (i+1)*int(time.Second), time.UTC)
		rootSpan.EndTime = rootSpan.StartTime.Add(2 * time.Second)

		children := make([]*Span, 0, spansPerTrace-1)
		for j := 0; j < spansPerTrace-1; j++ {
			// Each child span also gets ~payloadSize bytes of Input and Output
			// so that every span is ~1.5 KB regardless of role.
			prefix := fmt.Sprintf("c%d", j)
			children = append(children, &Span{
				SpanID:    fmt.Sprintf("%016x", (i+1)*10000+j+1),
				TraceID:   traceID,
				ProjectID: projectID,
				ParentID:  rootSpanID,
				SpanKind:  sampleKinds[j%len(sampleKinds)],
				Name:      fmt.Sprintf("tool-%s", sampleKinds[j%len(sampleKinds)]),
				Input:     strings.Repeat(prefix, (payloadSize+len(prefix))/len(prefix)),
				Output:    strings.Repeat(prefix, (payloadSize+len(prefix))/len(prefix)),
			})
			children[j].StartTime = rootSpan.StartTime.Add(time.Duration(j+1) * 100 * time.Millisecond)
			children[j].EndTime = children[j].StartTime.Add(500 * time.Millisecond)
		}

		allSpans := slices.Concat([]*Span{rootSpan}, children)
		traces = append(traces, &TraceGroup{
			TraceID: traceID,
			Spans:   allSpans,
		})
	}

	return traces
}

// TraceToNativeSpan converts a benchmark Span into the domain.Span type
// that the omneval SDK and ingest API expect.
func TraceToNativeSpan(s *Span) *domain.Span {
	return &domain.Span{
		SpanID:        s.SpanID,
		TraceID:       s.TraceID,
		ProjectID:     s.ProjectID,
		ParentID:      s.ParentID,
		Kind:          domain.SpanKind(s.SpanKind),
		Name:          s.Name,
		Input:         s.Input,
		Output:        s.Output,
		StartTime:     s.StartTime,
		EndTime:       s.EndTime,
		InputTokens:   256,
		OutputTokens:  256,
	}
}